  ('social-worker-moex-07121', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '文中「天下同歸而殊塗」，與下列選項何者意思相似？', '["條條大路通羅馬", "行百里者半九十", "有志者事竟成", "羅馬不是一天建成的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07122', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '這是一首漢朝的樂府詩：「戰城南，死郭北，野死不葬烏（烏鴉）可食。為我謂烏： 『且為客豪（「豪」通「嚎」）！野死諒不葬，腐肉安能去子逃？』」，詩人所關懷 的是下列何種議題？', '["反戰議題", "保育議題", "殯葬議題", "糧食議題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07123', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某位社會工作者試圖解構社會工作專業體制，反對專業霸權與社會控制，認為這些都會降低案主的自主 性。以上說法，傾向社會工作理論中的那一種觀點？', '["浪漫主義", "激進觀點", "生態系統論", "認知行為論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07124', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某實務工作者試圖為一位深受壞脾氣所苦的案主進行處遇。最後「改變不切實際的期待、修正不理性的 自我對話、加強問題解決和對策抉擇能力、與加強自我控制與管理」成為她處遇的目標。請問，她傾向 使用那種社會工作理論的觀點？', '["人本主義", "激進觀點", "生態系統論", "認知行為論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07125', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「功能、障礙與健康國際分類系統（簡稱ICF）」，主要是基於何種觀點，將障礙視為所有人都有可能在 生命歷程中經驗到的生命過程？', '["特殊主義", "普同主義", "人本主義", "菁英主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
