  ('social-worker-moex-07127', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「認為刑罰應該積極扮演移轉（Transition）犯罪人順利回歸社會之角色」是那一種刑罰本質的觀念？', '["嚇阻", "矯治", "重整", "修復"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
